import SweetAlertContext from './SweetAlertContext'
import React,{useState} from 'react'
import Swal from "sweetalert2";
import $ from "jquery";


function SweetAlertState(props) {
    const successAlert = () => {
        Swal.fire({
          title: "Good job!",
          text: "You clicked the button",
          icon: "success"
        });
      };
      const questionAlert = () => {
        Swal.fire({  
            title: 'Error',  
            text: 'Invalid Credentials !! Please Try Again',
            icon: 'error'
          }); 
    }
    const Address = () => {
        Swal.fire({  
            title: 'Great !',  
            text: 'Address Saved Successfully',
            icon: 'success'
          }); 
    }
    const Delete = () => {
        Swal.fire({  
            title: 'Great !',  
            text: 'Deleted Successfully',
            icon: 'success'
          }); 
    }
    const Register = () => {
        Swal.fire({  
            title: 'Great !',  
            text: 'Registration Successfull',
            icon: 'success'
          }); 
    }
    const upload = () => {
        Swal.fire({  
            title: 'Great !',  
            text: 'Product Uploaded Successfully',
            icon: 'success'
          }); 
    }
    const cart = () => {
        Swal.fire({  
            title: 'Great !',  
            text: 'Product Added To Cart Successfully',
            icon: 'success'
          }); 
    }
    const payment = () => {
      Swal.fire({  
          title: 'Great !',  
          text: 'Product Purchased Successfully',
          icon: 'success'
        }); 
  }
    const toggle =()=>{
        $('.cat-toggle').on('click', function () {
        $('.category-menu').slideToggle(500);
        return false;
          });}
    return (
        <SweetAlertContext.Provider value={{successAlert,questionAlert,Address,Delete,Register,upload,cart,toggle}}>
            {props.children};
        </SweetAlertContext.Provider>
    )
}

export default SweetAlertState
